mutation UpdateWorkerNodePool($payload: K8sUpdateWorkerNodePoolReq) {
  K8sUpdateWorkerNodePool(K8sUpdateWorkerNodePoolReq: $payload) {
    worker_node_pool {
      spec {
        name
        tags
        min_nodes
        max_nodes
        auto_scale
        num_nodes
        labels
        taints {
          key
          value
          effect
          __typename
        }
        __typename
      }
      uuid
      __typename
    }
    __typename
  }
}
